- (NSArray<NSString *> *)selectedFeatureCodesForBundleId:(NSString *)bundleId {
    if (bundleId.length == 0) return @[];
    NSString *key = [NSString stringWithFormat:@"SelectedFeatureCodes_%@", bundleId];
    NSString *hashedKey = [WBUtility getCodeNameSaltedSha1Hash:key];
    id value = [self.userDefaults objectForKey:hashedKey];
    if (![value isKindOfClass:NSArray.class]) return @[];
    NSMutableArray<NSString *> *codes = [NSMutableArray array];
    for (id obj in (NSArray *)value) {
        if ([obj isKindOfClass:NSString.class] && ((NSString *)obj).length > 0) {
            [codes addObject:obj];
        }
    }
    return codes.copy;
}

- (void)setSelectedFeatureCodes:(NSArray<NSString *> *)codes forBundleId:(NSString *)bundleId {
    if (bundleId.length == 0) return;
    NSString *key = [NSString stringWithFormat:@"SelectedFeatureCodes_%@", bundleId];
    NSString *hashedKey = [WBUtility getCodeNameSaltedSha1Hash:key];
    NSMutableArray<NSString *> *toStore = [NSMutableArray array];
    NSMutableSet<NSString *> *dedup = [NSMutableSet set];
    for (id obj in codes) {
        if (![obj isKindOfClass:NSString.class]) continue;
        NSString *code = (NSString *)obj;
        if (code.length == 0 || [dedup containsObject:code]) continue;
        [dedup addObject:code];
        [toStore addObject:code];
    }
    [self.userDefaults setObject:toStore forKey:hashedKey];
}

