    self.iconDisguiseSelectView.selected = NO;
    self.pretenseSelectView.selected = NO;
    self.oneclickSelectView.selected = NO;
    [self.selectedCodes removeAllObjects];
    [self.selectedCodes addObject:@"notification"];
    [self updateHasSelectedLabel];
}

- (void)handleConfirm {
    if ([self.delegate respondsToSelector:@selector(editFeaturesViewController:didConfirmSelectedCodes:)]) {
        [self.delegate editFeaturesViewController:self didConfirmSelectedCodes:[self.selectedCodes copy]];
    }
    [self dismiss];
}


#pragma mark - selection

- (void)featureSelectView:(WBEditFeaturesSelectView *)view didChangeSelected:(BOOL)selected {
    NSString *code = [self codeForView:view];
    if (selected) {
        if (![self.selectedCodes containsObject:code]) {
            if (self.selectedCodes.count >= WBFeaturesSelectedToShortcutMax) {
                [SVProgressHUD showInfoWithStatus:@"最多可选三种权益"];
                view.selected = NO;
                return;
            }
            [self.selectedCodes addObject:code];
        }
    } else {
        if ([self.selectedCodes containsObject:code] && self.selectedCodes.count <= 1) {
            [SVProgressHUD showInfoWithStatus:@"至少选择一种权益"];
            view.selected = YES;
            return;
        }
        [self.selectedCodes removeObject:code];
    }
    [self updateHasSelectedLabel];
}

- (NSString *)codeForView:(WBEditFeaturesSelectView *)view {
    if (view == self.notiSelectView) return @"notification";
    if (view == self.lockSelectView) return @"lock";
    if (view == self.iconDisguiseSelectView) return @"disguise";
    if (view == self.pretenseSelectView) return @"pretense";
    if (view == self.oneclickSelectView) return @"oneclick";
