- (void)jun_routeBuild:(JUNRouteBuilder *)route {
    [route name:@"profile" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        if (kStringIsEmpty(WBSettingManager.sharedManager.Mobile)) {
            WBLoginViewController *loginVC = [[WBLoginViewController alloc] init];
            WBMainViewController *mainVC = (WBMainViewController*)[WBAppManager getUIApplicationRootViewController];
            if (![mainVC isKindOfClass:[WBMainViewController class]]) {
                next(nil);
                return;
            }
            UINavigationController *loginNav = [[UINavigationController alloc] initWithRootViewController:loginVC];
            loginNav.modalPresentationStyle = UIModalPresentationFullScreen;
            [mainVC presentViewController:loginNav animated:YES completion:nil];
            next(nil);
        } else {
            WBPersonInfoViewController *personInfoVC = [[WBPersonInfoViewController alloc] init];
            [self.navigationController pushViewController:personInfoVC animated:YES];
            next(personInfoVC);
        }
    }];

    [route name:@"CustomerServiceByWeChatSDK" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        [self contactCustomerServiceByWeChatSDK];
    }];

    [route name:@"CustomerServiceByOldMethod" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        NSString *keyword = userInfo[@"keyword"];
        NSParameterAssert(!keyword || [keyword isKindOfClass:[NSString class]]);
        // 唤起客服
        [self contactCustomerService:keyword];
    }];
}

